#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int p, q;
        scanf("%d %d", &p, &q);
        int a[p], b[q], d[q];
        for (int i = 0; i < p; i++) scanf("%d", &a[i]);
        for (int i = 0; i < q; i++) scanf("%d %d", &b[i], &d[i]);
        int x[20];
        for (int i = 0; i < 10; i++) scanf("%d", &x[i]);
        for (int i = 10; i < 20; i++) {
            int sum = 0;
            for (int j = 0; j < p; j++) sum = (sum + a[j] * x[i - j - 1]) % 1000000;
            for (int j = 0; j < q; j++) sum = (sum + b[j] * (long long)(i + 1 - 10) * d[j]) % 1000000;
            x[i] = sum;
        }
        for (int i = 10; i < 20; i++) printf("%d ", x[i]);
        printf("\n");
    }
    return 0;
}

