import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int p = sc.nextInt();
            int q = sc.nextInt();
            int[] a = new int[p];
            int[] b = new int[q];
            int[] d = new int[q];
            for (int i = 0; i < p; i++) a[i] = sc.nextInt();
            for (int i = 0; i < q; i++) {
                b[i] = sc.nextInt();
                d[i] = sc.nextInt();
            }
            int[] x = new int[20];
            for (int i = 0; i < 10; i++) x[i] = sc.nextInt();
            for (int i = 10; i < 20; i++) {
                int sum = 0;
                for (int j = 0; j < p; j++) sum = (sum + a[j] * x[i - j - 1]) % 1000000;
                for (int j = 0; j < q; j++) sum = (sum + (long)b[j] * (i + 1 - 10) * d[j]) % 1000000;
                x[i] = sum;
            }
            for (int i = 10; i < 20; i++) System.out.print(x[i] + " ");
            System.out.println();
        }
    }
}

